SELECT branch, count() AS orders, sum(toFloat64(total_amount)) AS gross_revenue, sum(toFloat64(tax_amount)) AS tax_collected FROM rv.bv_order_canonical WHERE order_date IS NOT NULL GROUP BY branch ORDER BY gross_revenue DESC SETTINGS join_algorithm = 'partial_merge', max_bytes_before_external_group_by = 300000000, max_bytes_in_join = 300000000, max_memory_usage = 1800000000 FORMAT Null
